	if s == 0:
		return "cslnb"

	n_num = {}

	for item in arr:
		if item in n_num:
			n_num[item] += 1
		else:
			n_num[item] = 1

	if 0 in n_num and n_num[0] >= 2:
		return 'cslnb'

	for key in n_num.keys():
		if n_num[key] >= 3:
			return "cslnb"

	ind_pairs = []
	for key in n_num.keys():
		if n_num[key] == 2:
			ind_pairs.append(key)

	if len(ind_pairs) >= 2:
		return "cslnb"
	elif len(ind_pairs) == 1 and (ind_pairs[0]-1) in n_num:
		return "cslnb"
	else:
		# print('s', s)
		sum_targ = n*(n-1) // 2
		# print('sum_targ', sum_targ)
		dif_sum = s - sum_targ
		# print("dif_sum", dif_sum)
		if dif_sum % 2 == 0:
			return "cslnb"
		else:
			return "sjfnb"


